// ── CONFIGURE HERE ──────────────────────────────────
const ALPACA_KEY_ID     = 'PASTE_YOUR_KEY_ID_HERE';
const ALPACA_SECRET_KEY = 'PASTE_YOUR_SECRET_KEY_HERE';
const MASSIVE_API_KEY   = 'PASTE_YOUR_MASSIVE_KEY_HERE';
// ────────────────────────────────────────────────────

// Only run 4am–10:30am ET
const now = new Date();
const etHour = ((now.getUTCHours() - 5) + 24) % 24;
const etMin  = now.getUTCMinutes();
const etTime = etHour + etMin / 60;
if (etTime < 4 || etTime > 16.0) return [];

const alpacaHeaders = {
  'APCA-API-KEY-ID': ALPACA_KEY_ID,
  'APCA-API-SECRET-KEY': ALPACA_SECRET_KEY
};

// ── Step 1: Get today's top gainers from Massive ────
let candidates = [];
try {
  const today = new Date().toISOString().slice(0,10);
  const groupedResp = await fetch(
    `https://api.massive.com/v2/aggs/grouped/locale/us/market/stocks/${today}?adjusted=true&include_otc=false&apiKey=${MASSIVE_API_KEY}`
  );
  const groupedData = await groupedResp.json();
  const results = groupedData.results || [];
  candidates = results
    .filter(t => {
      const price = t.c || 0;
      const changePct = t.o > 0 ? (t.c - t.o) / t.o * 100 : 0;
      return price >= 0.10 && price <= 15.0 && changePct >= 8;
    })
    .sort((a,b) => {
      const ca = a.o > 0 ? (a.c - a.o) / a.o : 0;
      const cb = b.o > 0 ? (b.c - b.o) / b.o : 0;
      return cb - ca;
    })
    .map(t => t.T)
    .slice(0, 25);
} catch(e) {
  // Fallback: try Massive gainers snapshot
  try {
    const gainersResp = await fetch(
      `https://api.massive.com/v2/snapshot/locale/us/markets/stocks/gainers?apiKey=${MASSIVE_API_KEY}`
    );
    const gainersData = await gainersResp.json();
    const tickers = gainersData.tickers || [];
    candidates = tickers
      .filter(t => {
        const p = t.day?.c || t.lastTrade?.p || 0;
        return p >= 0.10 && p <= 15.0;
      })
      .map(t => t.ticker)
      .slice(0, 25);
  } catch(e2) { return []; }
}

if (candidates.length === 0) return [];

// ── Indicator helpers ────────────────────────────────
function emaArr(vals, p) {
  const k = 2 / (p + 1);
  const r = [vals[0]];
  for (let i = 1; i < vals.length; i++) r.push(vals[i]*k + r[i-1]*(1-k));
  return r;
}

function calcRSI(closes, p=14) {
  const ch = closes.map((c,i) => i===0?0:c-closes[i-1]).slice(1);
  let ag=0, al=0;
  for (let i=0;i<p;i++){ag+=Math.max(ch[i],0);al+=Math.max(-ch[i],0);}
  ag/=p; al/=p;
  const out=[];
  for (let i=p;i<ch.length;i++) {
    ag=(ag*(p-1)+Math.max(ch[i],0))/p;
    al=(al*(p-1)+Math.max(-ch[i],0))/p;
    out.push(al===0?100:100-100/(1+ag/al));
  }
  return out;
}

function calcStochRSI(closes, rp=14, sp=14, ks=3, ds=3) {
  const rsi=calcRSI(closes,rp);
  if (rsi.length < sp+ks+ds) return null;
  const rawK=[];
  for (let i=sp-1;i<rsi.length;i++) {
    const sl=rsi.slice(i-sp+1,i+1);
    const lo=Math.min(...sl), hi=Math.max(...sl);
    rawK.push(hi===lo?0:(rsi[i]-lo)/(hi-lo)*100);
  }
  const sK=[];
  for (let i=ks-1;i<rawK.length;i++) sK.push(rawK.slice(i-ks+1,i+1).reduce((a,b)=>a+b)/ks);
  const sD=[];
  for (let i=ds-1;i<sK.length;i++) sD.push(sK.slice(i-ds+1,i+1).reduce((a,b)=>a+b)/ds);
  if (sK.length < 2 || sD.length < 1) return null;
  return { k:sK[sK.length-1], kPrev:sK[sK.length-2], d:sD[sD.length-1] };
}

function calcZLSMA(closes, p=50) {
  if (closes.length < p*2) return null;
  const e1=emaArr(closes,p), e2=emaArr(e1,p);
  return 2*e1[e1.length-1]-e2[e2.length-1];
}

function shaIsGreen(bars) {
  const hc=bars.map(b=>(b.o+b.h+b.l+b.c)/4);
  const ho=[(bars[0].o+bars[0].c)/2];
  for (let i=1;i<bars.length;i++) ho.push((ho[i-1]+hc[i-1])/2);
  const sc=emaArr(emaArr(hc,10),10);
  const so=emaArr(emaArr(ho,10),10);
  return sc[sc.length-1]>so[so.length-1];
}

// ── Step 2: Check W118 conditions on each candidate ──
const signals = [];

for (const ticker of candidates) {
  try {
    const url = `https://data.alpaca.markets/v2/stocks/${ticker}/bars?timeframe=5Min&limit=100&feed=iex&adjustment=raw`;
    const resp = await fetch(url, { headers: alpacaHeaders });
    const data = await resp.json();
    const bars = data.bars;
    if (!bars || bars.length < 60) continue;

    const closes = bars.map(b=>b.c);
    const price  = closes[closes.length-1];

    // Guard: price still in range
    if (price < 0.10 || price > 15.0) continue;

    // 1. Stoch RSI K crosses above 20, K > D
    const srsi = calcStochRSI(closes);
    if (!srsi) continue;
    if (!(srsi.kPrev < 20 && srsi.k >= 20)) continue;
    if (srsi.k <= srsi.d) continue;

    // 2. Price above ZLSMA-50
    const zlsma = calcZLSMA(closes);
    if (!zlsma || price <= zlsma) continue;

    // 3. SHA green
    if (!shaIsGreen(bars)) continue;

    // 4. Volume >= 1.5x 20-bar avg
    const vols   = bars.slice(-21,-1).map(b=>b.v);
    const avgVol = vols.reduce((a,b)=>a+b)/vols.length;
    const curVol = bars[bars.length-1].v;
    if (curVol < avgVol*1.5) continue;

    // 5. K was below 10 within last 3 bars (deep reset confirmation)
    const closes3 = closes.slice(-4,-1);
    const srsiDeep = calcStochRSI(closes.slice(0,-1));
    const kWasLow = srsiDeep && srsiDeep.kPrev < 10;

    signals.push({ json: {
      ticker, price,
      stop : parseFloat((price*0.92).toFixed(2)),
      t1   : parseFloat((price*1.15).toFixed(2)),
      t2   : parseFloat((price*1.30).toFixed(2)),
      t3   : parseFloat((price*1.60).toFixed(2)),
      qty:10, qty_t1:3, qty_t2:3, qty_t3:4,
      k          : srsi.k.toFixed(1),
      d          : srsi.d.toFixed(1),
      vol_ratio  : (curVol/avgVol).toFixed(1),
      deep_reset : kWasLow,
      ALPACA_KEY_ID, ALPACA_SECRET_KEY
    }});
  } catch(e) { /* skip */ }
}

return signals;

